// figmaapi.js
import axios from 'axios';

const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB';
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA';
const BUTTON_NODE_ID = 'YOUR_BUTTON_NODE_ID';

export const fetchButtonData = async (nodeId) => {
    try {
        const response = await axios.get(
            `https://api.figma.com/v1/files/${FILE_ID}/nodes?ids=${nodeId}`,
            {
                headers: { 'X-Figma-Token': FIGMA_TOKEN },
            }
        );
        const rawData = response.data.nodes[nodeId]?.document;
        return rawData;
    } catch (error) {
        console.error('Error fetching button data:', error);
        throw error;
    }
};
